// Prepare scene data for sliding window processing + fetch style_dna
const scenes = $('Load Pending Scenes').all().map(i => i.json);
const topicId = $('Webhook Trigger').item.json.body.topic_id;

if (!Array.isArray(scenes) || scenes.length === 0) {
  return [{
    json: {
      scenes: [],
      topic_id: topicId,
      total_scenes: 0,
      scenes_completed: 0,
      scenes_failed: 0,
      total_image_cost: 0,
      skip_processing: true,
      style_dna: '',
    }
  }];
}

// Fetch project style_dna
const projectId = scenes[0].project_id;
let styleDna = '';
try {
  const resp = await this.helpers.httpRequest({
    method: 'GET',
    url: `${$env.SUPABASE_URL}/rest/v1/projects?id=eq.${projectId}&select=style_dna`,
    headers: {
      'apikey': $env.SUPABASE_ANON_KEY,
      'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
    },
  });
  if (resp && resp[0] && resp[0].style_dna) {
    styleDna = resp[0].style_dna;
  }
} catch (e) {
  // style_dna is optional — continue without it
}

return [{
  json: {
    scenes: scenes,
    topic_id: scenes[0].topic_id,
    project_id: projectId,
    total_scenes: scenes.length,
    scenes_completed: 0,
    scenes_failed: 0,
    total_image_cost: 0,
    skip_processing: false,
    style_dna: styleDna,
  }
}];

// Parallel completion sync: check if ALL image scenes are done
// v4.0: All scenes are static_image (I2V/T2V deprecated)
// After images complete, fires Ken Burns instead of assembly
const { execFileSync } = require('child_process');

const data = $input.first().json;
const topicId = data.topic_id || $('Webhook Trigger').item.json.body.topic_id;
const projectId = data.project_id || $('Webhook Trigger').item.json.body.project_id;
const hdr = ['-H', 'apikey: ' + $env.SUPABASE_ANON_KEY, '-H', 'Authorization: Bearer ' + $env.SUPABASE_SERVICE_ROLE_KEY];

const supaGet = (path) => JSON.parse(execFileSync('curl', ['-s', $env.SUPABASE_URL + '/rest/v1/' + path, ...hdr]).toString());

if (data.stopped) {
  return [{ json: { ...data, topic_id: topicId, project_id: projectId, assembly_claimed: false, reason: 'stopped' } }];
}

// All scenes are static_image now — done when image_status=uploaded or skipped
const imagesDone = supaGet('scenes?topic_id=eq.' + topicId + '&image_status=eq.uploaded&select=id');
const skipped = supaGet('scenes?topic_id=eq.' + topicId + '&skipped=eq.true&select=id');
const completedCount = (Array.isArray(imagesDone) ? imagesDone.length : 0) + (Array.isArray(skipped) ? skipped.length : 0);

const totalScenes = supaGet('scenes?topic_id=eq.' + topicId + '&select=id');
const totalCount = Array.isArray(totalScenes) ? totalScenes.length : 0;

let assemblyClaimed = false;
if (completedCount >= totalCount && totalCount > 0) {
  // Update pipeline_stage to 'images' (completed)
  execFileSync('curl', ['-s', '-X', 'PATCH', $env.SUPABASE_URL + '/rest/v1/topics?id=eq.' + topicId, ...hdr, '-H', 'Content-Type: application/json', '-H', 'Prefer: return=minimal', '-d', JSON.stringify({ pipeline_stage: 'images', images_progress: 'complete' })]);
  assemblyClaimed = true; // Will trigger Ken Burns next
}

return [{ json: { ...data, topic_id: topicId, project_id: projectId, completed_visual_scenes: completedCount, total_visual_scenes: totalCount, assembly_claimed: assemblyClaimed } }];

// Fire sub-workflow for each scene — 2 at a time, 10s between batches
// Avoids Fal.ai 429 rate limits
// Now uses 3-part cinematic prompt: composition_prefix + image_prompt + style_dna
const { execFileSync, execSync } = require('child_process');

const data = $input.first().json;
const scenes = data.scenes || [];
const topicId = data.topic_id;
const projectId = data.project_id;
const styleDna = data.style_dna || '';
const webhookUrl = 'http://localhost:5678/webhook/process-scene/image';
const token = $env.DASHBOARD_API_TOKEN;

// Universal negative prompt (prevents artifacts, text, style drift)
const NEGATIVE_PROMPT = 'text, watermark, signature, logo, UI elements, blurry, low quality, distorted faces, extra fingers, mutated hands, bad anatomy, deformed, disfigured, out of frame, cropped, duplicate, error, jpeg artifacts, low resolution, cartoon, anime, painting, illustration, 3D render, CGI';

const BATCH_SIZE = 2;
const BATCH_DELAY_SEC = 10;
let fired = 0;

for (let i = 0; i < scenes.length; i += BATCH_SIZE) {
  const batch = scenes.slice(i, i + BATCH_SIZE);

  for (const scene of batch) {
    // Build 3-part cinematic prompt
    const prefix = scene.composition_prefix || '';
    const subject = scene.image_prompt || '';
    const parts = [prefix, subject, styleDna].filter(Boolean);
    const fullPrompt = parts.join(' ');

    try {
      execFileSync('curl', [
        '-s', '-o', '/dev/null',
        '-X', 'POST', webhookUrl,
        '-H', 'Content-Type: application/json',
        '-H', 'Authorization: Bearer ' + token,
        '-d', JSON.stringify({
          scene_id: scene.id,
          image_prompt: fullPrompt,
          negative_prompt: NEGATIVE_PROMPT,
          topic_id: topicId,
          project_id: projectId
        }),
        '--connect-timeout', '3',
        '--max-time', '5'
      ]);
      fired++;
    } catch (e) { /* fire-and-forget */ }
  }

  // Wait between batches (skip wait after last batch)
  if (i + BATCH_SIZE < scenes.length) {
    execSync('sleep ' + BATCH_DELAY_SEC);
  }
}

return [{ json: { topic_id: topicId, project_id: projectId, fired, total: scenes.length, batch_size: BATCH_SIZE, delay_sec: BATCH_DELAY_SEC, has_style_dna: !!styleDna } }];

